export const AIRLINE_OPTIONS = AIRLINES.map((a) => ({
  value: a.code,
  label: `${a.code} — ${a.name}`,
}));

export function getAirlineByCode(code: string): Airline | undefined {
  return AIRLINES.find((a) => a.code === code);
}
